def _sage_maker_feature_group_to_nested(
    sage_maker_feature_group: SageMakerFeatureGroup,
) -> SageMakerFeatureGroupNested:
    """Convert flat SageMakerFeatureGroup to nested format."""
    attrs = SageMakerFeatureGroupAttributes()
    _populate_sage_maker_feature_group_attrs(attrs, sage_maker_feature_group)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        sage_maker_feature_group,
        _SAGE_MAKER_FEATURE_GROUP_REL_FIELDS,
        SageMakerFeatureGroupRelationshipAttributes,
    )
    return SageMakerFeatureGroupNested(
        guid=sage_maker_feature_group.guid,
        type_name=sage_maker_feature_group.type_name,
        status=sage_maker_feature_group.status,
        version=sage_maker_feature_group.version,
        create_time=sage_maker_feature_group.create_time,
        update_time=sage_maker_feature_group.update_time,
        created_by=sage_maker_feature_group.created_by,
        updated_by=sage_maker_feature_group.updated_by,
        classifications=sage_maker_feature_group.classifications,
        classification_names=sage_maker_feature_group.classification_names,
        meanings=sage_maker_feature_group.meanings,
        labels=sage_maker_feature_group.labels,
        business_attributes=sage_maker_feature_group.business_attributes,
        custom_attributes=sage_maker_feature_group.custom_attributes,
        pending_tasks=sage_maker_feature_group.pending_tasks,
        proxy=sage_maker_feature_group.proxy,
        is_incomplete=sage_maker_feature_group.is_incomplete,
        provenance_type=sage_maker_feature_group.provenance_type,
        home_id=sage_maker_feature_group.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _sage_maker_feature_group_from_nested(
    nested: SageMakerFeatureGroupNested,
) -> SageMakerFeatureGroup:
    """Convert nested format to flat SageMakerFeatureGroup."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SageMakerFeatureGroupAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAGE_MAKER_FEATURE_GROUP_REL_FIELDS,
        SageMakerFeatureGroupRelationshipAttributes,
    )
    return SageMakerFeatureGroup(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_sage_maker_feature_group_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sage_maker_feature_group_to_nested_bytes(
    sage_maker_feature_group: SageMakerFeatureGroup, serde: Serde
) -> bytes:
    """Convert flat SageMakerFeatureGroup to nested JSON bytes."""
    return serde.encode(_sage_maker_feature_group_to_nested(sage_maker_feature_group))


def _sage_maker_feature_group_from_nested_bytes(
    data: bytes, serde: Serde
) -> SageMakerFeatureGroup:
    """Convert nested JSON bytes to flat SageMakerFeatureGroup."""
    nested = serde.decode(data, SageMakerFeatureGroupNested)
    return _sage_maker_feature_group_from_nested(nested)


